const phoneNumber = "60162763172";
const message = "Hi! I need help with my parcel ID: " + {{tracking_id}};
// encodeURIComponent makes sure the spaces don't turn into random code
const url = "https://wa.me/" + phoneNumber + "?text=" + encodeURIComponent(message);

window.open(url, '_blank');

// 1. Define the variables from Typebot
const id = {{tracking_id}};
const problem = {{issue_type}};
const name = {{user_name}}; 
const description = {{description}};// Optional: if you collected the user's name

// 2. Build the Body Template
// %0A is the code for a "New Line"
let bodyContent = "Dear LogistiCare Support Team,%0A%0A";
bodyContent += "I would like to file an official report regarding my delivery.%0A%0A";
bodyContent += "----------------------------%0A";
bodyContent += "USER DETAILS%0A";
bodyContent += "----------------------------%0A";
bodyContent += "Tracking ID: " + id + "%0A";
bodyContent += "Issue Category: "+ {{issue_type}}+ "%0A";
  bodyContent += "Description: " + description + "%0A%0A";
bodyContent += "Please assist me with this matter as soon as possible.%0A%0A";
bodyContent += "Best regards,%0A";
bodyContent += name;

// 3. Execute the Redirect
window.location.href = "mailto:tp081915@mail.apu.edu.my?subject=Official Support Request - " + id + "&body=" + bodyContent;
